    <link rel="preconnect" href="https://fonts.googleapis.com">
    <link rel="preconnect" href="https://fonts.gstatic.com" crossorigin>
    <link href="https://fonts.googleapis.com/css2?family=Open+Sans:ital,wght@0,300..800;1,300..800&display=swap"
        rel="stylesheet">
    <link rel="stylesheet" type="text/css" href="5026241088.css">
    <style>
        .open-sans-judul {
    font-family: "Open Sans", sans-serif;
    font-optical-sizing: auto;
    font-weight: 400;
    font-style: normal;
    font-variation-settings: "wdth"100;
    text-align: center;
    padding-top: 60px;
    padding-bottom: 70px;
}

body {
    background-color: rgb(241, 241, 241);
}

.container2 {
    background-color: white;
    margin-top: 30px;
    margin-bottom: 30px;
    padding-left: 100px;
    padding-right: 100px;
}

.foto {
    margin: auto;
    border-radius: 50%;
    margin-top: 0px;
    width: 70px;
}


.open-sans-kalimat {
    font-family: "Open Sans", sans-serif;
    font-optical-sizing: auto;
    font-weight: 300;
    font-style: italic;
    font-variation-settings: "wdth"100;
    font-size: 14px;
}

.open-sans-nama {
    font-family: "Open Sans", sans-serif;
    font-optical-sizing: auto;
    font-weight: 600;
    font-style: normal;
    font-variation-settings: "wdth"100;
    text-transform: uppercase;
    font-size: 14px;
}

.open-sans-role {
    font-family: "Open Sans", sans-serif;
    font-optical-sizing: auto;
    font-weight: 350;
    font-style: italic;
    font-variation-settings: "wdth"100;
    font-size: 12px;
}

.logo {
    margin-left: -100px;
    margin-right: -100px;
    background-color: rgb(230, 230, 230);
    padding: 20px;
    padding-left: 200px;
    padding-right: 200px;
}

.isi {
    padding-bottom: 100px;
    padding-right: 50px;
    padding-left: 50px;
}

.frame-logo {
    display: flex;
    justify-content: center;
    align-items: center;
    height: 120px;
}

.keterangan{
    padding-left: 50px;
}
    </style>
</head>

<body>

    <div class="container">
