                    <!--logo 1-->
                    <div class="col frame-logo">
                        <img width="170px"
                            src="https://upload.wikimedia.org/wikipedia/commons/thumb/e/e6/Pertamina_Logo.svg/1280px-Pertamina_Logo.svg.png">
                    </div>
                    <!--logo 2-->
                    <div class="col border frame-logo">
                        <img width="80px" src="https://upload.wikimedia.org/wikipedia/commons/9/97/Logo_PLN.png">
                    </div>
                    <!--logo 3-->
                    <div class="col frame-logo">
                        <img width="120px"
                            src="https://katamata.wordpress.com/wp-content/uploads/2009/01/logo-its-biru-transparan.png">
                    </div>
                    <!--logo 4-->
                    <div class="col frame-logo">
                        <img width="120px"
                            src="data:image/jpeg;base64,">
                    </div>
                    <!--logo 5-->
                    <div class="col frame-logo">
                        <img width="80px"
                            src="data:image/jpeg;base64,">
                    </div>
                </div>
